import React, { useEffect, useState } from "react";
import Navbar from "../components/Navbar";
import { api } from "../lib/api";
import { Link } from "react-router-dom";

export default function Landing() {
  const [stats, setStats] = useState({ projects: 0, members: 0 });

  useEffect(() => {
    (async () => {
      try {
        const [p, u] = await Promise.allSettled([
          api.get("/projects"),
          // members count is admin-only; this fallback is fine for landing
        ]);
        if (p.status === "fulfilled") setStats((s) => ({ ...s, projects: p.value.data.length }));
      } catch {}
    })();
  }, []);

  return (
    <section className="relative h-screen w-full overflow-hidden bg-black" data-testid="landing-hero">
      <video
        className="absolute inset-0 w-full h-full object-cover"
        autoPlay
        loop
        muted
        playsInline
        src="https://d8j0ntlcm91z4.cloudfront.net/user_38xzZboKViGWJOttwIXH07lWA1P/hf_20260418_063509_7d167302-4fd4-480b-8260-18ab572333d4.mp4"
      />
      <div className="absolute inset-0 bg-black/30 pointer-events-none" />

      <Navbar />

      <div className="relative h-full w-full">
        <h1 className="hero-title absolute text-white font-medium text-[14vw] md:text-[13vw] left-4 md:left-10 top-[18%]" data-testid="hero-word-1">build</h1>
        <h1 className="hero-title absolute text-white font-medium text-[14vw] md:text-[13vw] right-4 md:right-10 top-[38%]" data-testid="hero-word-2">forge</h1>
        <h1 className="hero-title absolute text-white font-medium text-[14vw] md:text-[13vw] left-[18%] md:left-[28%] top-[58%]" data-testid="hero-word-3">future</h1>

        <p className="absolute left-6 md:left-10 top-[46%] max-w-[240px] text-[15px] leading-snug text-white/90" data-testid="hero-tagline">
          a tech club where curious builders forge tomorrow's hardware, software and everything in between.
        </p>

        <div className="absolute right-6 md:right-24 top-[14%]">
          <div className="flex items-center gap-3 justify-end">
            <span className="hidden md:block h-px w-24 bg-white/40 rotate-[20deg]" />
            <span className="text-4xl md:text-5xl font-medium tracking-tight" data-testid="stat-members-value">+120</span>
          </div>
          <div className="text-xs md:text-sm text-white/70 mt-1 text-right">active members</div>
        </div>

        <div className="absolute left-6 md:left-20 bottom-20 md:bottom-24" data-testid="stat-projects">
          <div className="flex items-center gap-3">
            <span className="text-4xl md:text-5xl font-medium tracking-tight">+{stats.projects || 14}</span>
            <span className="hidden md:block h-px w-24 bg-white/40 rotate-[-20deg]" />
          </div>
          <div className="text-xs md:text-sm text-white/70 mt-1">projects shipped</div>
        </div>

        <div className="absolute right-6 md:right-20 bottom-16 md:bottom-20">
          <div className="flex items-center gap-3 justify-end">
            <span className="hidden md:block h-px w-24 bg-white/40 rotate-[-20deg]" />
            <span className="text-4xl md:text-5xl font-medium tracking-tight">+8</span>
          </div>
          <div className="text-xs md:text-sm text-white/70 mt-1 text-right">hackathons hosted</div>
        </div>

        <Link
          to="/projects"
          data-testid="hero-cta-projects"
          className="absolute left-6 md:left-10 bottom-6 md:bottom-8 text-white/70 hover:text-white text-sm transition-colors"
        >
          → see what we've built
        </Link>
      </div>

      <div className="pointer-events-none absolute bottom-0 left-0 right-0 h-48 bg-gradient-to-b from-transparent to-black" />
    </section>
  );
}
